#!/usr/bin/env python3import os, json, anthropic, smtplib, timefrom email.mime.multipart import MIMEMultipartfrom email.mime.text import MIMETextfrom datetime import datetimeHOLDINGS = [    {"ticker": "NVDA", "company": "NVIDIA Corp", "shares": 8.0009, "cost": 192.89},    {"ticker": "CEG", "company": "Constellation Energy", "shares": 4.0099, "cost": 385.57},    {"ticker": "FNDE", "company": "Schwab Fundamental Emerging Markets ETF", "shares": 111, "cost": 35.95},    {"ticker": "QQQ", "company": "Invesco QQQ TR", "shares": 3.0078, "cost": 605.45},    {"ticker": "CGGR", "company": "Capital Group Growth ETF", "shares": 89, "cost": 44.89},    {"ticker": "QTUM", "company": "Defiance Quantum ETF", "shares": 2, "cost": 114.56},    {"ticker": "SWEGX", "company": "Schwab MarketTrack All Equity", "shares": 88.797, "cost": 24.07}]RECIPIENT = os.environ["EMAIL_RECIPIENT"]ANTHROPIC_KEY = os.environ["ANTHROPIC_API_KEY"]def run_research():    client = anthropic.Anthropic(api_key=ANTHROPIC_KEY)    today = datetime.now().strftime("%A, %B %d, %Y")    tickers = [h["ticker"] for h in HOLDINGS]    ticker_str = ", ".join(tickers)    price_res = client.messages.create(        model="claude-sonnet-4-20250514", max_tokens=1500,        tools=[{"type": "web_search_20250305", "name": "web_search"}],        messages=[{"role": "user", "content": "Today is " + today + ". Find current prices for: " + ticker_str + ", SPY, QQQ, VIX, GLD. Return ONLY JSON: {\"prices\": {\"AAPL\": {\"price\": 189.50, \"change_pct\": 1.2}}}"}]    )    price_json = {}    for block in price_res.content:        if block.type == "text":            txt = block.text.strip()            try:                s, e = txt.index("{"), txt.rindex("}")                price_json = json.loads(txt[s:e+1])
